{"content":"package kotlinx.coroutines

import kotlin.test.*
import kotlin.coroutines.*

class IsActiveTest {
    @Test
    fun testIsActiveWithoutJob() {
        val ctx = EmptyCoroutineContext
        // CoroutineContext.isActive
        assertFalse(ctx.isActive, "CoroutineContext.isActive should be false currently (the issue we're addressing)")

        val scope = object : CoroutineScope {
            override val coroutineContext: CoroutineContext = EmptyCoroutineContext
        }
        // CoroutineScope.isActive
        assertTrue(scope.isActive, "CoroutineScope.isActive is true even without Job")
    }
}
